ps.pstext:
if !IsFeatureImplemented(FEAT_SVE) && !IsFeatureImplemented(FEAT_SME) then
    EndOfDecode(Decode_UNDEF);
end;
let esize : integer{} = 8;
let g : integer = UInt(Pg);
let n : integer = UInt(Pn);
let m : integer = UInt(Pm);
let d : integer = UInt(Pd);
let setflags : boolean = TRUE;

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mask : bits(PL) = P{}(g);
let operand1 : bits(PL) = P{}(n);
let operand2 : bits(PL) = P{}(m);
var result : bits(PL);
var last : boolean = (LastActive{PL}(mask, operand1, 8) == '1');

for e = 0 to elements-1 do
    if ActivePredicateElement{PL}(mask, e, 8) then
        last = last && (!ActivePredicateElement{PL}(operand2, e, 8));
        let pbit : bit = if last then '1' else '0';
        result[e*:1] = ZeroExtend{1}(pbit);
    else
        result[e*:1] = ZeroExtend{1}('0');
    end;
end;

if setflags then
    PSTATE.[N,Z,C,V] = PredTest{PL}(mask, result, esize);
end;
P{PL}(d) = result;
